/**
 * Shared, client-safe catalog data and helpers.
 *
 * This module contains NO server-only imports (no `better-sqlite3`, no `node:*`)
 * so it is safe to bundle into the client. The cart *state* is never stored here;
 * only the fixed product catalog and pure formatting helpers live in this file.
 */

export interface Product {
  id: string;
  name: string;
  price: number;
}

/** A single line of the shopping cart. */
export interface CartItem {
  productId: string;
  quantity: number;
}

/** The fixed product catalog that the page renders. */
export const PRODUCTS: Product[] = [
  { id: "tshirt", name: "Qwik T-Shirt", price: 20.0 },
  { id: "stickers", name: "Sticker Pack", price: 5.0 },
  { id: "mug", name: "Coffee Mug", price: 12.5 },
];

/** Quick id -> product lookup. */
export const PRODUCT_MAP: Record<string, Product> = Object.fromEntries(
  PRODUCTS.map((p) => [p.id, p]),
);

/**
 * Format a monetary amount (in dollars) as `$X.XX` with exactly two decimals.
 * Computed from integer cents to avoid floating-point rounding surprises.
 */
export function formatPrice(dollars: number): string {
  const cents = Math.round(dollars * 100);
  return `$${(cents / 100).toFixed(2)}`;
}

/**
 * Server-only SQLite persistence layer.
 *
 * IMPORTANT: This module imports `better-sqlite3` and uses `node:path`, so it
 * must NEVER be imported from the top level of a component module that is also
 * rendered in the browser. It is only ever loaded through dynamic `import()`
 * from inside `server$()` / `routeLoader$()` boundaries, which run exclusively
 * on the server.
 */
import path from "node:path";
import Database from "better-sqlite3";
import type { CartItem } from "../catalog";

/**
 * The SQLite database file lives inside the project directory so the cart
 * persists across server restarts and page reloads.
 */
const DB_PATH = path.join(process.cwd(), "cart.db");

const db = new Database(DB_PATH);
// WAL mode gives better concurrency and durability for a local file.
db.pragma("journal_mode = WAL");

db.exec(`
  CREATE TABLE IF NOT EXISTS cart_items (
    session_id  TEXT NOT NULL,
    product_id  TEXT NOT NULL,
    quantity    INTEGER NOT NULL,
    PRIMARY KEY (session_id, product_id)
  )
`);

/** Read every cart line for a session, in insertion order. */
export function getCart(sessionId: string): CartItem[] {
  const rows = db
    .prepare(
      "SELECT product_id AS productId, quantity FROM cart_items WHERE session_id = ? ORDER BY rowid",
    )
    .all(sessionId) as Array<{ productId: string; quantity: number }>;
  return rows.map((r) => ({ productId: r.productId, quantity: r.quantity }));
}

/**
 * Add a product to the cart. If the product is already present, its quantity is
 * incremented by one instead of creating a duplicate line.
 */
export function addItem(sessionId: string, productId: string): void {
  db.prepare(
    `INSERT INTO cart_items (session_id, product_id, quantity)
     VALUES (?, ?, 1)
     ON CONFLICT(session_id, product_id)
     DO UPDATE SET quantity = cart_items.quantity + 1`,
  ).run(sessionId, productId);
}

/**
 * Change a cart line's quantity by `delta`. The quantity is clamped to a
 * minimum of 1 (the decrement button must never lower the quantity below 1).
 */
export function updateQty(sessionId: string, productId: string, delta: number): void {
  db.prepare(
    `UPDATE cart_items
       SET quantity = MAX(1, quantity + ?)
     WHERE session_id = ? AND product_id = ?`,
  ).run(delta, sessionId, productId);
}

/** Remove a product line entirely from the cart. */
export function removeItem(sessionId: string, productId: string): void {
  db.prepare(
    "DELETE FROM cart_items WHERE session_id = ? AND product_id = ?",
  ).run(sessionId, productId);
}

/**
 * Server-only session helpers.
 *
 * Only a *type* is imported from `@builder.io/qwik-city` (erased at compile
 * time) and `node:crypto` is loaded via dynamic `import()`, so this module is
 * safe to reference from `server$()` bodies without leaking into the client
 * bundle.
 */
import type { RequestEvent } from "@builder.io/qwik-city";

export const SESSION_COOKIE = "session_id";

/**
 * Returns the visitor's session id, creating and cookie-setting it on the
 * first write when the cookie is absent.
 */
export async function ensureSession(event: RequestEvent): Promise<string> {
  let sessionId = event.cookie.get(SESSION_COOKIE);
  if (!sessionId) {
    const { randomUUID } = await import("node:crypto");
    sessionId = randomUUID();
    event.cookie.set(SESSION_COOKIE, sessionId, {
      path: "/",
      httpOnly: true,
      sameSite: "lax",
      maxAge: 60 * 60 * 24 * 365,
    });
  }
  return sessionId;
}

import {
  component$,
  useComputed$,
  useStore,
  type QRL,
} from "@builder.io/qwik";
import {
  routeLoader$,
  server$,
  type DocumentHead,
  type RequestEventLoader,
} from "@builder.io/qwik-city";
import {
  PRODUCTS,
  PRODUCT_MAP,
  formatPrice,
  type CartItem,
} from "../catalog";
import { SESSION_COOKIE, ensureSession } from "../server/session";

/**
 * Loads the visitor's cart from SQLite during SSR so the page renders with the
 * persisted cart and survives a full reload. This is a read: it does NOT create
 * a session if the cookie is absent.
 */
export const useCart = routeLoader$(async (event: RequestEventLoader) => {
  const sessionId = event.cookie.get(SESSION_COOKIE);
  if (!sessionId) return [];
  const { getCart } = await import("../server/db");
  return getCart(sessionId);
});

/**
 * Read the cart for the current session (no session is created on read).
 */
const getCartServer = server$(async function (): Promise<CartItem[]> {
  const sessionId = this.cookie.get(SESSION_COOKIE);
  if (!sessionId) return [];
  const { getCart } = await import("../server/db");
  return getCart(sessionId);
});

/**
 * Add a product to the cart. Creates the session cookie on this first write.
 * Returns the full, refreshed cart so the client can update its store in one
 * round trip.
 */
const addToCart = server$(async function (productId: string): Promise<CartItem[]> {
  const sid = await ensureSession(this);
  const { addItem, getCart } = await import("../server/db");
  addItem(sid, productId);
  return getCart(sid);
});

/**
 * Increment (+1) or decrement (-1) a cart line's quantity. The quantity is
 * clamped to a minimum of 1 on the server.
 */
const updateQtyServer = server$(
  async function (productId: string, delta: number): Promise<CartItem[]> {
    const sid = await ensureSession(this);
    const { updateQty, getCart } = await import("../server/db");
    updateQty(sid, productId, delta);
    return getCart(sid);
  },
);

/**
 * Remove a product line entirely from the cart.
 */
const removeFromCartServer = server$(
  async function (productId: string): Promise<CartItem[]> {
    const sid = await ensureSession(this);
    const { removeItem, getCart } = await import("../server/db");
    removeItem(sid, productId);
    return getCart(sid);
  },
);

export default component$(() => {
  // Initial cart comes from the server (routeLoader) during SSR.
  const initialCart = useCart();

  // The cart lives in a useStore; mutations replace its `items` array.
  const cart = useStore<{ items: CartItem[] }>({ items: initialCart.value });

  // Live total derived reactively from the store.
  const total = useComputed$(() => {
    const dollars = cart.items.reduce((sum, item) => {
      const product = PRODUCT_MAP[item.productId];
      return sum + (product ? product.price * item.quantity : 0);
    }, 0);
    return formatPrice(dollars);
  });

  const refresh = $(async (result: CartItem[]) => {
    cart.items = result;
  });

  const handleAdd = $(async (productId: string) => {
    refresh(await addToCart(productId));
  });

  const handleUpdateQty = $(async (productId: string, delta: number) => {
    refresh(await updateQtyServer(productId, delta));
  });

  const handleRemove = $(async (productId: string) => {
    refresh(await removeFromCartServer(productId));
  });

  return (
    <main style={{ "max-width": "720px", margin: "0 auto", padding: "1rem" }}>
      <h1>Qwik Store</h1>

      <section>
        <h2>Products</h2>
        <ul style={{ listStyle: "none", padding: 0 }}>
          {PRODUCTS.map((product) => (
            <li
              key={product.id}
              style={{
                display: "flex",
                "justify-content": "space-between",
                alignItems: "center",
                padding: "0.5rem 0",
                borderBottom: "1px solid #eee",
              }}
            >
              <span>
                {product.name} — {formatPrice(product.price)}
              </span>
              <button
                data-testid={`add-${product.id}`}
                onClick$={() => handleAdd(product.id)}
              >
                Add to cart
              </button>
            </li>
          ))}
        </ul>
      </section>

      <section>
        <h2>Cart</h2>

        {cart.items.length === 0 ? (
          <p data-testid="empty-cart">Your cart is empty.</p>
        ) : (
          <ul style={{ listStyle: "none", padding: 0 }}>
            {cart.items.map((item) => {
              const product = PRODUCT_MAP[item.productId];
              return (
                <li
                  key={item.productId}
                  data-testid={`cart-item-${item.productId}`}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "0.5rem",
                    padding: "0.5rem 0",
                    borderBottom: "1px solid #eee",
                  }}
                >
                  <span style={{ flex: 1 }}>
                    {product ? product.name : item.productId} —{" "}
                    {product ? formatPrice(product.price) : ""}
                  </span>
                  <button
                    data-testid={`dec-${item.productId}`}
                    onClick$={() => handleUpdateQty(item.productId, -1)}
                    aria-label={`Decrease ${item.productId} quantity`}
                  >
                    −
                  </button>
                  <span data-testid={`qty-${item.productId}`}>{item.quantity}</span>
                  <button
                    data-testid={`inc-${item.productId}`}
                    onClick$={() => handleUpdateQty(item.productId, 1)}
                    aria-label={`Increase ${item.productId} quantity`}
                  >
                    +
                  </button>
                  <button
                    data-testid={`remove-${item.productId}`}
                    onClick$={() => handleRemove(item.productId)}
                  >
                    Remove
                  </button>
                </li>
              );
            })}
          </ul>
        )}

        <p>
          Total: <span data-testid="cart-total">{total.value}</span>
        </p>
      </section>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Qwik Store",
  meta: [
    {
      name: "description",
      content: "Server-persisted shopping cart built with Qwik City.",
    },
  ],
};

// Tell the type-checker that the QRL helpers above are used.
export type _ = QRL;

